// Extract email fields and generate idempotency key from Message-ID header.
// Duplicate emails (same messageKey) are silently skipped.
const email = items[0].json;
const rawId = email.messageId || (email.subject + email.date);
const messageKey = Buffer.from(rawId).toString('base64').replace(/[^a-zA-Z0-9]/g, '').slice(0, 24);

// Idempotency check — skip if already processed in last 24h
const staticData = $getWorkflowStaticData('global');
if (!staticData.processed) staticData.processed = {};
const entry = staticData.processed[messageKey];
if (entry && (Date.now() - entry.ts) < 86400000) {
  console.log('[Silent Concierge] Skipping duplicate:', messageKey);
  return [];
}

const body = email.text
  || (email.html ? email.html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim() : '')
  || '(no body)';

return [{
  json: {
    messageKey,
    fromEmail: email.from || '',
    fromName: email.fromName || '',
    replyTo: email.replyTo || email.from || '',
    subject: email.subject || '(sin asunto)',
    body: body.slice(0, 3000), // cap at 3k chars for Gemini
    receivedAt: new Date().toISOString()
  }
}];

