// Parse Gemini response and store draft in static data.
const geminiRaw = items[0].json;
let draft;
try {
  const text = geminiRaw.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  draft = JSON.parse(text);
} catch (e) {
  throw new Error('[Silent Concierge] Gemini returned invalid JSON: ' + e.message);
}

if (!draft.draftBody || !draft.draftSubject) {
  throw new Error('[Silent Concierge] Gemini response missing required fields');
}

// Store draft in workflow static data keyed by messageKey
const ctx = $('Extract & Deduplicate').first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
staticData.drafts[ctx.messageKey] = {
  ts: Date.now(),
  fromEmail: ctx.fromEmail,
  fromName: ctx.fromName,
  replyTo: ctx.replyTo,
  originalSubject: ctx.subject,
  draftSubject: draft.draftSubject,
  draftBody: draft.draftBody,
  language: draft.language,
  intent: draft.intent
};

return [{
  json: {
    messageKey: ctx.messageKey,
    fromEmail: ctx.fromEmail,
    fromName: ctx.fromName,
    intent: draft.intent,
    language: draft.language,
    draftSubject: draft.draftSubject,
    draftBody: draft.draftBody
  }
}];

